     1	using System.Security.Claims;
     2	using InventoryFlow.Application.Common.Tenancy;
     3	using InventoryFlow.Domain.Entities;
     4	using InventoryFlow.Infrastructure.Persistence;
     5	using Microsoft.AspNetCore.Http;
     6	using Microsoft.EntityFrameworkCore;
     7	
     8	namespace InventoryFlow.Infrastructure.Tenancy;
     9	
    10	/// <summary>Resolves a request workspace exclusively from authenticated membership data.</summary>
    11	public sealed class CurrentWorkspaceResolver(IHttpContextAccessor httpContextAccessor, ApplicationDbContext dbContext) : ICurrentWorkspace
    12	{
    13	    /// <inheritdoc />
    14	    public async Task<CurrentWorkspace?> GetAsync(CancellationToken cancellationToken = default)
    15	    {
    16	        var userIdValue = httpContextAccessor.HttpContext?.User.FindFirstValue(ClaimTypes.NameIdentifier);
    17	        if (!Guid.TryParse(userIdValue, out var userId)) return null;
    18	        var matches = await (from member in dbContext.WorkspaceMembers.AsNoTracking()
    19	                             join workspace in dbContext.Workspaces.AsNoTracking() on member.WorkspaceId equals workspace.Id
    20	                             where member.UserId == userId && member.Role == WorkspaceMemberRole.Owner
    21	                             select new CurrentWorkspace(workspace.Id, workspace.Name)).Take(2).ToListAsync(cancellationToken);
    22	        return matches.Count == 1 ? matches[0] : null;
    23	    }
    24	}
