    10	{ public async Task<AuthenticationSession> Handle(LoginUserCommand request, CancellationToken cancellationToken) => await service.LoginAsync(request, cancellationToken) ?? throw new AuthenticationException(); }
    11	/// <summary>Delegates refresh to the authentication port.</summary>
