    13	{ public Task<AuthenticationSession?> Handle(RefreshSessionCommand request, CancellationToken cancellationToken) => service.RefreshAsync(request.RefreshToken, cancellationToken); }
    14	/// <summary>Delegates logout to the authentication port.</summary>
