   119	        using var registration = await RegisterAsync();
   120	        var refreshCookie = GetRefreshCookieValue(registration);
   121	
   122	        // Act
   123	        using var logout = await SendWithRefreshCookieAsync(HttpMethod.Post, "/api/auth/logout", refreshCookie);
   124	        using var refresh = await RefreshAsync(refreshCookie);
   125	
   126	        // Assert
   127	        Assert.Equal(HttpStatusCode.NoContent, logout.StatusCode);
