   131	    /// <summary>
   132	    /// Permits only one concurrent refresh and treats the other request as replay.
   133	    /// </summary>
   134	    [Fact]
   135	    public async Task Refresh_ConcurrentRequests_OnlyOneSucceedsAndRevokesFamily()
   136	    {
   137	        // Arrange
   138	        using var registration = await RegisterAsync();
   139	        var originalCookie = GetRefreshCookieValue(registration);
   140	
   141	        // Act
   142	        var refreshes = await Task.WhenAll(
   143	            RefreshAsync(originalCookie),
   144	            RefreshAsync(originalCookie));
   145	        using var first = refreshes[0];
   146	        using var second = refreshes[1];
   147	        var successfulRefresh = refreshes.Single(response => response.StatusCode == HttpStatusCode.OK);
   148	        var replacementCookie = GetRefreshCookieValue(successfulRefresh);
   149	        using var descendant = await RefreshAsync(replacementCookie);
   150	
   151	        // Assert
   152	        Assert.Single(refreshes, response => response.StatusCode == HttpStatusCode.OK);
   153	        Assert.Single(refreshes, response => response.StatusCode == HttpStatusCode.Unauthorized);
   154	        Assert.Equal(HttpStatusCode.Unauthorized, descendant.StatusCode);
