   159	    /// </summary>
   160	    [Fact]
   161	    public async Task Logout_ConcurrentWithRefresh_RevokesOriginalAndAnyReplacement()
   162	    {
   163	        // Arrange
   164	        using var registration = await RegisterAsync();
   165	        var originalCookie = GetRefreshCookieValue(registration);
   166	        var start = new TaskCompletionSource(TaskCreationOptions.RunContinuationsAsynchronously);
   167	
   168	        // Act
   169	        var logoutTask = StartWhenReleasedAsync(
   170	            start.Task,
   171	            () => SendWithRefreshCookieAsync(HttpMethod.Post, "/api/auth/logout", originalCookie));
   172	        var refreshTask = StartWhenReleasedAsync(start.Task, () => RefreshAsync(originalCookie));
   173	        start.SetResult();
   174	
   175	        using var logout = await logoutTask;
   176	        using var refresh = await refreshTask;
   177	        var issuedCookies = new List<string> { originalCookie };
   178	        if (refresh.StatusCode == HttpStatusCode.OK)
   179	        {
   180	            issuedCookies.Add(GetRefreshCookieValue(refresh));
   181	        }
   182	
   183	        var refreshAttempts = await Task.WhenAll(issuedCookies.Select(RefreshAsync));
   184	        using var originalAttempt = refreshAttempts[0];
   185	        if (refreshAttempts.Length > 1)
   186	        {
   187	            using var replacementAttempt = refreshAttempts[1];
   188	            Assert.Equal(HttpStatusCode.Unauthorized, replacementAttempt.StatusCode);
   189	        }
   190	
   191	        // Assert
   192	        Assert.Equal(HttpStatusCode.NoContent, logout.StatusCode);
   193	        Assert.True(
   194	            refresh.StatusCode is HttpStatusCode.OK or HttpStatusCode.Unauthorized,
   195	            $"Expected refresh to succeed or be unauthorized, but received {refresh.StatusCode}.");
   196	        Assert.Equal(HttpStatusCode.Unauthorized, originalAttempt.StatusCode);
   197	    }
   198	
   199	    private static async Task<T> StartWhenReleasedAsync<T>(Task start, Func<Task<T>> operation)
   200	    {
   201	        await start;
   202	        return await operation();
   203	    }
   204	
   205	    private async Task<HttpResponseMessage> RegisterAsync()
   206	    {
   207	        var suffix = Guid.NewGuid().ToString("N");
   208	        return await _client.PostAsJsonAsync(
   209	            "/api/auth/register",
   210	            new RegisterUserCommand($"User {suffix}", $"user-{suffix}@example.test", "Password!12345"));
   211	    }
   212	
   213	    private async Task<HttpResponseMessage> RefreshAsync(string refreshCookie) =>
   214	        await SendWithRefreshCookieAsync(HttpMethod.Post, "/api/auth/refresh", refreshCookie);
   215	
   216	    private async Task<HttpResponseMessage> SendWithRefreshCookieAsync(
   217	        HttpMethod method,
   218	        string path,
   219	        string refreshCookie)
   220	    {
   221	        using var request = new HttpRequestMessage(method, path);
   222	        request.Headers.Add("Cookie", $"{RefreshCookieName}={refreshCookie}");
   223	        return await _client.SendAsync(request);
   224	    }
   225	
   226	    private static async Task<AuthenticationResponse> ReadSessionAsync(HttpResponseMessage response)
   227	    {
   228	        var session = await response.Content.ReadFromJsonAsync<AuthenticationResponse>(JsonOptions);
   229	        return Assert.IsType<AuthenticationResponse>(session);
   230	    }
   231	
   232	    private static string GetRefreshCookieHeader(HttpResponseMessage response) =>
   233	        Assert.Single(response.Headers.GetValues("Set-Cookie"));
   234	
   235	    private static string GetRefreshCookieValue(HttpResponseMessage response)
   236	    {
   237	        var header = GetRefreshCookieHeader(response);
   238	        var cookie = header.Split(';', 2)[0].Split('=', 2);
   239	        Assert.Equal(RefreshCookieName, cookie[0]);
   240	        return Uri.UnescapeDataString(cookie[1]);
   241	    }
   242	}
