    19	/// <summary>
    20	/// Registers infrastructure-layer services.
    21	/// </summary>
    22	public static class InfrastructureServiceCollectionExtensions
    23	{
    24	    /// <summary>
    25	    /// Adds SQL Server persistence and ASP.NET Core Identity services.
    26	    /// </summary>
    27	    /// <param name="services">The dependency-injection service collection.</param>
    28	    /// <param name="configuration">The application configuration.</param>
    29	    /// <returns>The supplied <paramref name="services"/> instance.</returns>
    30	    /// <exception cref="ArgumentException">Thrown when the database connection string is missing.</exception>
    31	    public static IServiceCollection AddInfrastructure(
    32	        this IServiceCollection services,
    33	        IConfiguration configuration)
    34	    {
    35	        ArgumentNullException.ThrowIfNull(services);
    36	        ArgumentNullException.ThrowIfNull(configuration);
    37	
    38	        var connectionString = configuration.GetConnectionString("InventoryFlowDatabase");
    39	        ArgumentException.ThrowIfNullOrWhiteSpace(
    40	            connectionString,
    41	            "ConnectionStrings:InventoryFlowDatabase");
    42	
    43	        services.AddOptions<JwtOptions>()
    44	            .Bind(configuration.GetSection(JwtOptions.SectionName))
    45	            .ValidateDataAnnotations()
    46	            .Validate(options => Encoding.UTF8.GetByteCount(options.SigningKey) >= 32, "Jwt signing key must be at least 32 bytes.")
    47	            .ValidateOnStart();
    48	        var jwt = configuration.GetSection(JwtOptions.SectionName).Get<JwtOptions>() ?? new JwtOptions();
    49	
    50	        services.AddAuthentication(JwtBearerDefaults.AuthenticationScheme)
    51	            .AddJwtBearer(options =>
    52	            {
    53	                options.TokenValidationParameters = new TokenValidationParameters
    54	                {
    55	                    ValidateIssuer = true,
    56	                    ValidIssuer = jwt.Issuer,
    57	                    ValidateAudience = true,
    58	                    ValidAudience = jwt.Audience,
    59	                    ValidateIssuerSigningKey = true,
    60	                    IssuerSigningKey = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(jwt.SigningKey)),
    61	                    ValidateLifetime = true,
    62	                    ClockSkew = TimeSpan.Zero,
    63	                    NameClaimType = "display_name"
    64	                };
    65	            });
    66	        services.AddHttpContextAccessor();
    67	        services.AddSingleton(TimeProvider.System);
    68	        services.AddScoped<ICurrentWorkspace, CurrentWorkspaceResolver>();
    69	        services.AddScoped<JwtAccessTokenIssuer>();
    70	        services.AddSingleton<RefreshTokenGenerator>();
    71	        services.AddScoped<IAuthenticationService, IdentityAuthenticationService>();
    72	
    73	        services.AddDbContext<ApplicationDbContext>(options => options.UseSqlServer(
    74	            connectionString,
    75	            sqlServerOptions => sqlServerOptions.EnableRetryOnFailure()));
    76	        services.AddDataProtection()
    77	            .SetApplicationName("InventoryFlow")
    78	            .PersistKeysToDbContext<ApplicationDbContext>();
    79	
    80	        services.AddIdentityCore<ApplicationUser>(options =>
    81	            {
    82	                options.User.RequireUniqueEmail = true;
    83	                options.Password.RequiredLength = 12;
    84	                options.Password.RequireDigit = true;
    85	                options.Password.RequireLowercase = true;
    86	                options.Password.RequireUppercase = true;
    87	                options.Password.RequireNonAlphanumeric = true;
